mapper.select:
SELECT TS.SERVICE_ID, TS.WORK_CD, TS.CAR_NO, TS.COMPANY_ID, TC.COMPANY_NM, TO_CHAR(TS.REQUEST_DT, 'MM.DD HH24:MI') AS REQUEST_DT, TO_CHAR(TS.PROC_DT, 'YYYYMMDD') AS PROC_DT, TS.PROC_ST FROM TR_SERVICE TS, TM_COMPANY TC WHERE TS.COMPANY_ID = TC.COMPANY_ID AND TS.WORK_CD LIKE 'CE%' AND TS.WORK_CD NOT LIKE 'CERS%' AND TS.REQUEST_DT BETWEEN TO_DATE(#{START_DT} || '00:00:00', 'YYYYMMDDHH24:MI:SS') AND TO_DATE(#{END_DT} || '23:59:59', 'YYYYMMDDHH24:MI:SS')
AND TS.COMPANY_ID = #{COMPANY_ID}
AND TS.PROC_ST = #{PROC_ST}
ORDER BY TS.REQUEST_DT DESC
